INSERT INTO compliance_rules (framework_short,rule_id,description,regex_pattern,url_check,severity,citation_url,enforcement_example,rule_type,trigger_pattern,fine_low_gbp,fine_high_gbp,layman_explanation,tamazia_fix_short,service_page_path,pricing_tier,active,sector_relevance,created_at) VALUES
('US_STATE_PRIVACY','SP_GPC','Honour the Global Privacy Control universal opt-out signal','(global privacy control|\bgpc\b|universal opt[- ]?out|opt[- ]?out preference signal)','homepage','P1','https://oag.ca.gov/privacy/ccpa','California, Colorado and Connecticut launched a joint 2025 sweep against businesses that ignore Global Privacy Control opt-outs; 11+ states now require honouring it.','trigger_then_check','(google ads|meta pixel|facebook|targeted ad|advertis|third[- ]party|analytics|_ga|fbq)',6000,16000,'Most US privacy states now require your site to detect and honour the Global Privacy Control browser signal for opting out of data sale/sharing. Your site shows no GPC handling, the exact failure the CA/CO/CT joint sweep is targeting.','Tamazia implements server- and client-side GPC detection wired to your opt-out.','/services/compliance','scale',TRUE,NULL,now()),
('US_STATE_PRIVACY','SP_DONOTSELL','"Do Not Sell or Share" / "Your Privacy Choices" opt-out link','(do not sell|do not share|your privacy choices|opt[- ]out of (the )?(sale|sharing))','homepage','P1','https://oag.ca.gov/privacy/ccpa','Selling/sharing data for cross-context advertising without the opt-out link draws USD 2,500 per violation (USD 7,500 intentional) and is a top CPPA enforcement area.','trigger_then_check','(google ads|meta pixel|targeted ad|advertis|third[- ]party (advertis|cookies)|share your (data|information))',6000,16000,'If you share data with ad networks and serve US consumers, the CCPA/CPRA and sister state laws require a clear "Do Not Sell or Share / Your Privacy Choices" link. Yours is missing.','Tamazia adds a compliant opt-out link wired to GPC and your ad tags.','/services/compliance','scale',TRUE,NULL,now()),
('US_STATE_PRIVACY','SP_NOTICE','State-compliant privacy notice (categories, purposes, rights, opt-out methods)','(privacy (policy|notice)|categories of (personal )?(data|information)|we collect|how we use)','homepage','P1','https://www.osano.com/us-data-privacy-laws','The 20 in-force state privacy laws require a notice covering data categories, purposes, rights and opt-out methods; fines to USD 7,500/violation (USD 20,000 in Colorado).','trigger_then_check','(privacy|we collect|personal (data|information)|contact (us|form)|sign ?up)',6000,16000,'The 20 US states with privacy laws require a notice listing the categories of data, purposes, consumer rights and how to opt out. Your notice does not meet that multi-state baseline.','Tamazia builds a multi-state US privacy notice covering every required disclosure.','/services/compliance','scale',TRUE,NULL,now()),
('US_STATE_PRIVACY','SP_RIGHTS','Consumer rights (access, delete, correct, opt-out, appeal) + request method','(right to (access|delete|correct|opt[- ]out)|submit a (request|privacy request)|appeal|exercise your rights)','homepage','P2','https://www.osano.com/us-data-privacy-laws','State laws grant access, deletion, correction, opt-out and (in most) an appeal right; failure to provide a request method is finable.','trigger_then_check','(privacy|personal (data|information)|we collect)',6000,16000,'US state laws give consumers rights to access, delete, correct and opt out, plus an appeal route. Your site offers no clear way to exercise them.','Tamazia adds a consumer-rights request workflow meeting the state requirements.','/services/compliance','scale',TRUE,NULL,now()),
('US_STATE_PRIVACY','SP_SENSITIVE','Opt-in / limit for sensitive data (Nebraska, Maryland MODPA, others)','(sensitive (data|information)|limit the use of (my|your) sensitive|opt[- ]?in.{0,30}sensitive|strict necessity)','homepage','P2','https://www.osano.com/us-data-privacy-laws','Nebraska requires opt-in for sensitive data; Maryland MODPA (Oct 2025) adds strict data-minimisation and expansive sensitive-data definitions.','trigger_then_check','(health|biometric|precise location|race|religion|sexual|genetic|fingerprint)',6000,16000,'If you process sensitive data (health, biometrics, precise location), states like Nebraska and Maryland require opt-in and strict necessity. Your site has no such control.','Tamazia adds sensitive-data opt-in and a data-minimisation posture.','/services/compliance','scale',TRUE,NULL,now()),
('US_ATTORNEY_ADVERTISING','ATTY_MISLEADING','No false or misleading statements about the lawyer or services (ABA 7.1)','(no win no fee|guarantee|guaranteed|best (lawyer|attorney|firm)|#1|number one|always win|100% success)','homepage','P1','https://www.americanbar.org/groups/professional_responsibility/publications/model_rules_of_professional_conduct/rule_7_1_communications_concerning_a_lawyer_s_services/','ABA Model Rule 7.1 and state bars prohibit false or misleading communications; firms were disciplined in 2024-25 for unsubstantiated website claims.','trigger_then_check','(attorney|law firm|lawyer|legal services|practice areas|counsel|esq)',NULL,NULL,'ABA Model Rule 7.1 (adopted by state bars) bans false or misleading claims. Superlative or guarantee-style language on your site risks a bar complaint.','Tamazia rewrites attorney-advertising copy to a Rule 7.1-compliant, substantiated form.','/services/compliance','scale',TRUE,'{legal,law-firms}',now()),
('US_ATTORNEY_ADVERTISING','ATTY_RESULTS','Past-results / testimonial disclaimer','(prior results|past results|results may vary|no guarantee of (a similar )?(outcome|result)|results depend)','homepage','P2','https://www.americanbar.org/groups/professional_responsibility/publications/model_rules_of_professional_conduct/rule_7_1_communications_concerning_a_lawyer_s_services/','Most state bars require a disclaimer that prior results do not guarantee a similar outcome when results/testimonials are advertised.','trigger_then_check','(verdict|settlement|\$\d|recovered|won|case result|testimonial|client (review|success))',NULL,NULL,'If you advertise case results or testimonials, most US state bars require a "prior results do not guarantee a similar outcome" disclaimer. Yours is missing.','Tamazia adds the required results/testimonial disclaimer.','/services/compliance','scale',TRUE,'{legal,law-firms}',now()),
('US_MEDICAL_BOARD','MED_CLAIMS','No misleading treatment claims; accurate board-certification statements','(board[- ]certified|pain[- ]?free|guaranteed|permanent (results|cure)|safe and effective|no (risk|downtime)|miracle)','homepage','P1','https://www.ftc.gov/business-guidance/resources/health-products-compliance-guidance','State medical/dental boards and the FTC act against misleading treatment claims and inaccurate board-certification statements.','trigger_then_check','(clinic|dental|dentist|aesthetic|cosmetic|treatment|surgery|botox|filler|implant|dermatolog|physician|md\b)',NULL,NULL,'US medical and dental boards and the FTC prohibit misleading treatment claims and inaccurate board-certification statements. Some phrasing on your site crosses that line.','Tamazia rewrites medical claims to a substantiated, board-compliant form.','/services/compliance','scale',TRUE,'{healthcare,dental,wellness,medical}',now()),
('US_MEDICAL_BOARD','MED_TESTIMONIAL','Testimonial + before/after disclosures (FTC + boards)','(results (not )?typical|individual results (may )?vary|paid (testimonial|endorsement)|#ad|material connection|not a typical (result|patient))','homepage','P2','https://www.ftc.gov/business-guidance/resources/ftcs-endorsement-guides-what-people-are-asking','FTC Endorsement Guides + state boards require typicality and material-connection disclosures on patient testimonials and before/after imagery.','trigger_then_check','(before (and|&) after|patient (review|testimonial|story)|transformation|results gallery|5[- ]star)',NULL,NULL,'Patient testimonials and before/after images need typicality and material-connection disclosures under the FTC guides and medical-board rules. Yours lack them.','Tamazia adds compliant testimonial and before/after disclosures.','/services/compliance','scale',TRUE,'{healthcare,dental,wellness,medical}',now())
